ui_sabotage_t ui_spy_sabotage_ask(struct game_s *g, int spy, int target, planet_id_t *planetptr)
{
    /* 1oom-mp: ask the spying human what to sabotage + where (default none outside MP) */
    if (g_mp_decision_hook) {
        struct { int32_t spy, target; } rq;
        struct { int32_t act; uint16_t planet; } rs = { 0, PLANET_NONE };
        rq.spy = spy; rq.target = target;
        int r = g_mp_decision_hook(spy, MP_DEC_SPY_SABOTAGE, &rq, sizeof(rq), &rs, sizeof(rs));
        if (r >= (int)sizeof(rs)) {
            if (planetptr) { *planetptr = (planet_id_t)rs.planet; }
            return (ui_sabotage_t)rs.act;
        }
    }
    /* relay failed (e.g. the spying client dropped): do NOTHING, not a factory sabotage. 0 is
       UI_SABOTAGE_FACT; UI_SABOTAGE_NONE is -1. Returning 0 here made a dropped client trigger a
       bogus FACT sabotage on PLANET_NONE. */
    if (planetptr) { *planetptr = PLANET_NONE; }
    return UI_SABOTAGE_NONE;
}

int ui_spy_sabotage_done(struct game_s *g, int pi, int spy, int target, ui_sabotage_t act, int other1, int other2, planet_id_t planet, int snum)
{
    /* 1oom-mp: this BLOCKING result is for the saboteur ONLY, never the victim here -- the victim is
       notified via the non-blocking ui_spy_sabotage_show path instead (MP_DEC_SPY_RESULT_SHOW, buffered
       + replayed at their turn start). It can't be relayed here because the victim's screen
       (game_spy_sab_human's second loop) is a blocking popup on a passive player; relaying it deadlocks
       resolution waiting for a "continue" ack that can't come (it renders black), and it fires bogusly
       for an incited revolt. Discriminate by `target`: the saboteur views the TARGET empire's planet
       (pi != target), the victim views their OWN planet (pi == target). Do NOT key on `spy` -- in the
       victim call that argument is sabotage_spy (a caught-magnitude number, not a player id) and
       collides with real ids like player 0. The screen reads post-sabotage planet state the client
       doesn't have yet, so we ship a one-planet snapshot with the params. */
    if (g_mp_decision_hook && !IS_AI(g, pi) && (pi != target) && (planet < g->galaxy_stars)) {
        struct { int32_t spy, target, act, other1, other2, snum, planet; planet_t psnap; } rq;
        int32_t other = PLAYER_NONE;
        memset(&rq, 0, sizeof(rq));
        rq.spy = spy; rq.target = target; rq.act = (int32_t)act;
        rq.other1 = other1; rq.other2 = other2; rq.snum = snum; rq.planet = (int32_t)planet;
        rq.psnap = g->planet[planet];
        BOOLVEC_SET1(rq.psnap.within_srange, pi); /* force "in range" so the client shows the current (post-sabotage) numbers */
        int r = g_mp_decision_hook(pi, MP_DEC_SPY_RESULT, &rq, (int)sizeof(rq), &other, (int)sizeof(other));
        if (r >= (int)sizeof(other)) { return (int)other; }
    }
    return PLAYER_NONE;
}

void ui_spy_sabotage_show(struct game_s *g, int pi, int spy, int target, ui_sabotage_t act, int other1, int other2, planet_id_t planet, int snum)
{
    /* 1oom-mp: non-blocking buffered variant of ui_spy_sabotage_done. Used at the saboteur's result when
       no framing choice is needed (other2 == PLAYER_NONE), so the return value is irrelevant. The client
       buffers it + instant-acks and replays at state load (with the snapshot swapped in), so the
       saboteur's result screen never blocks the other player. Ships the post-sabotage planet snapshot
       exactly like the blocking version. */
    if (g_mp_decision_hook && !IS_AI(g, pi) && (planet < g->galaxy_stars)) {
        struct { int32_t spy, target, act, other1, other2, snum, planet; planet_t psnap; } rq;
        uint8_t ack = 0;
        memset(&rq, 0, sizeof(rq));
        rq.spy = spy; rq.target = target; rq.act = (int32_t)act;
        rq.other1 = other1; rq.other2 = other2; rq.snum = snum; rq.planet = (int32_t)planet;
        rq.psnap = g->planet[planet];
        BOOLVEC_SET1(rq.psnap.within_srange, pi); /* force "in range" so the client shows post-sabotage numbers */
        g_mp_decision_hook(pi, MP_DEC_SPY_RESULT_SHOW, &rq, (int)sizeof(rq), &ack, 1);
    }
}

