bool ui_bomb_ask(struct game_s *g, int pi, planet_id_t planet_i, int pop_inbound)
{
    /* 1oom-mp: ask the attacking human's client whether to bomb (the server blocks
       on the answer). Default "no" outside MP (g_mp_decision_hook NULL). */
    if (g_mp_decision_hook) {
        uint8_t req[8], resp = 0;
        req[0] = (uint8_t)(pi >> 8);          req[1] = (uint8_t)pi;
        req[2] = (uint8_t)(planet_i >> 8);    req[3] = (uint8_t)planet_i;
        req[4] = (uint8_t)(pop_inbound >> 24); req[5] = (uint8_t)(pop_inbound >> 16);
        req[6] = (uint8_t)(pop_inbound >> 8);  req[7] = (uint8_t)pop_inbound;
        int r = g_mp_decision_hook(pi, MP_DEC_BOMB, req, 8, &resp, 1);
        return (r >= 1) && (resp != 0);
    }
    return false;
}

void ui_bomb_show(struct game_s *g, int pi, int attacker_i, int owner_i, planet_id_t planet_i, int popdmg, int factdmg, bool play_music, bool hide_other)
{
    /* 1oom-mp: the server resolves the bombing on this null UI, so relay the result (pop killed /
       factories destroyed) to the human attacker AND the human owner, who each render it. */
    (void)pi;
    if (g_mp_decision_hook_multi) {
        int players[2], n = 0;
        int cand[2]; cand[0] = attacker_i; cand[1] = owner_i;
        for (int k = 0; k < 2; ++k) {
            int p = cand[k];
            if ((p < 0) || (p >= (int)g->players) || !IS_HUMAN(g, p)) { continue; }
            bool dup = false;
            for (int j = 0; j < n; ++j) { if (players[j] == p) { dup = true; break; } }
            if (!dup) { players[n++] = p; }
        }
        if ((n > 0) && (planet_i < g->galaxy_stars)) {
            /* ship the params + a snapshot of the bombed planet: ui_bomb_show reads the planet's live
               owner, which can flip to NONE when a bombing depopulates it, so the client patches this
               in to render correctly at replay-time regardless of later same-turn changes. */
            struct { int32_t attacker, owner, planet, popdmg, factdmg; uint8_t play_music, hide_other; planet_t psnap; } req;
            uint8_t resp[2] = {0, 0};
            memset(&req, 0, sizeof(req));
            req.attacker = attacker_i; req.owner = owner_i; req.planet = (int32_t)planet_i;
            req.popdmg = popdmg; req.factdmg = factdmg;
            req.play_music = play_music ? 1 : 0; req.hide_other = hide_other ? 1 : 0;
            req.psnap = g->planet[planet_i];
            g_mp_decision_hook_multi(players, n, MP_DEC_BOMB_SHOW, &req, (int)sizeof(req), resp, 1);
        }
    }
}

bool ui_bomb_ask_batch(struct game_s *g, const struct ui_bomb_target_s *targets, int n, bool *decided)
{
    /* 1oom-mp: fan the whole turn's target list out to every human attacker AT ONCE (parallel) so both
       players decide their bombings simultaneously rather than one-at-a-time. Each client prompts for
       ITS own targets and returns a u64 yes/no bitmask (bit k = bomb targets[k]); demux per attacker. */
    if ((!g_mp_decision_hook_multi) || (n <= 0)) { return false; }
    if (n > 64) { n = 64; }
    {
        int players[8], np = 0;
        for (int k = 0; k < n; ++k) {
            int a = targets[k].attacker;
            bool dup = false;
            if ((a < 0) || (a >= (int)g->players) || (!IS_HUMAN(g, a))) { continue; }
            for (int j = 0; j < np; ++j) { if (players[j] == a) { dup = true; break; } }
            if ((!dup) && (np < 8)) { players[np++] = a; }
        }
        if (np == 0) { return false; }
        {
            static uint8_t req[4 + 64 * sizeof(struct ui_bomb_target_s)];
            uint8_t resp[8 * 8];
            int32_t n32 = n;
            memset(resp, 0, sizeof(resp));
            memcpy(req, &n32, 4);
            memcpy(req + 4, targets, (size_t)n * sizeof(struct ui_bomb_target_s));
            g_mp_decision_hook_multi(players, np, MP_DEC_BOMB_BATCH, req, 4 + n * (int)sizeof(struct ui_bomb_target_s), resp, 8);
            for (int k = 0; k < n; ++k) {
                int a = targets[k].attacker, pidx = -1;
                uint64_t mask = 0;
                for (int j = 0; j < np; ++j) { if (players[j] == a) { pidx = j; break; } }
                if (pidx >= 0) { memcpy(&mask, resp + pidx * 8, 8); }
                decided[k] = (((mask >> k) & 1) != 0);
            }
        }
    }
    return true;
}

bool ui_spy_sabotage_batch(struct game_s *g, const struct ui_spy_sab_target_s *targets, int n, struct ui_spy_sab_dec_s *out)
{
    /* 1oom-mp: fan the whole turn's sabotage-opportunity list out to every human spymaster AT ONCE
       (parallel) so both players pick their sabotage simultaneously rather than one-at-a-time. Each
       client answers for ITS own opportunities (act+planet) and returns a ui_spy_sab_dec_s[n] array;
       demux opportunity k from its saboteur-player's slot. Mirrors ui_bomb_ask_batch. */
    if ((!g_mp_decision_hook_multi) || (n <= 0)) { return false; }
    if (n > 32) { n = 32; }
    {
        int players[8], np = 0;
        for (int k = 0; k < n; ++k) {
            int a = targets[k].player;
            bool dup = false;
            if ((a < 0) || (a >= (int)g->players) || (!IS_HUMAN(g, a))) { continue; }
            for (int j = 0; j < np; ++j) { if (players[j] == a) { dup = true; break; } }
            if ((!dup) && (np < 8)) { players[np++] = a; }
        }
        if (np == 0) { return false; }
        {
            static uint8_t req[4 + 32 * sizeof(struct ui_spy_sab_target_s)];
            static uint8_t resp[8 * 32 * sizeof(struct ui_spy_sab_dec_s)];
            int32_t n32 = n;
            int rlen = n * (int)sizeof(struct ui_spy_sab_dec_s);
            memset(resp, 0, sizeof(resp));
            memcpy(req, &n32, 4);
            memcpy(req + 4, targets, (size_t)n * sizeof(struct ui_spy_sab_target_s));
            int rc = g_mp_decision_hook_multi(players, np, MP_DEC_SPY_SABOTAGE_BATCH, req, 4 + n * (int)sizeof(struct ui_spy_sab_target_s), resp, rlen);
            for (int k = 0; k < n; ++k) {
                int a = targets[k].player, pidx = -1;
                /* safe default: a dropped client leaves its slot at the memset 0, which would decode to
                   act=0 (UI_SABOTAGE_FACT) on planet 0 -- a real factory sabotage. Default to NONE and
                   only trust the slots when the whole batch succeeded (rc == 0 => every player answered). */
                out[k].act = -1; out[k].planet = PLANET_NONE;
                if (rc != 0) { continue; }
                for (int j = 0; j < np; ++j) { if (players[j] == a) { pidx = j; break; } }
                if (pidx >= 0) {
                    memcpy(&out[k], resp + pidx * rlen + k * (int)sizeof(struct ui_spy_sab_dec_s), sizeof(struct ui_spy_sab_dec_s));
                }
            }
        }
    }
    return true;
}

bool ui_spy_steal_batch(struct game_s *g, const struct ui_spy_steal_target_s *targets, int n, int16_t *out)
{
    /* 1oom-mp: fan the whole turn's steal-opportunity list out to every human spy AT ONCE (parallel)
       so both players pick which tech to steal simultaneously rather than one-at-a-time. Each client
       answers for ITS own opportunities (chosen field) and returns an int16_t[n] array; demux
       opportunity k from its spy-player's slot. Mirrors ui_spy_sabotage_batch. */
    if ((!g_mp_decision_hook_multi) || (n <= 0)) { return false; }
    if (n > 32) { n = 32; }
    {
        int players[8], np = 0;
        for (int k = 0; k < n; ++k) {
            int a = targets[k].spy;
            bool dup = false;
            if ((a < 0) || (a >= (int)g->players) || (!IS_HUMAN(g, a))) { continue; }
            for (int j = 0; j < np; ++j) { if (players[j] == a) { dup = true; break; } }
            if ((!dup) && (np < 8)) { players[np++] = a; }
        }
        if (np == 0) { return false; }
        {
            static uint8_t req[4 + 32 * sizeof(struct ui_spy_steal_target_s)];
            static int16_t resp[8 * 32];
            int32_t n32 = n;
            int rlen = n * (int)sizeof(int16_t);
            memset(resp, 0, sizeof(resp));
            memcpy(req, &n32, 4);
            memcpy(req + 4, targets, (size_t)n * sizeof(struct ui_spy_steal_target_s));
            int rc = g_mp_decision_hook_multi(players, np, MP_DEC_SPY_STEAL_BATCH, req, 4 + n * (int)sizeof(struct ui_spy_steal_target_s), (uint8_t *)resp, rlen);
            for (int k = 0; k < n; ++k) {
                int a = targets[k].spy, pidx = -1;
                /* -1 = steal nothing. A dropped client leaves its slot at 0 (= field 0, a real steal);
                   only trust the slots when the whole batch succeeded (rc == 0 => every player answered). */
                if (rc != 0) { out[k] = -1; continue; }
                for (int j = 0; j < np; ++j) { if (players[j] == a) { pidx = j; break; } }
                out[k] = (pidx >= 0) ? resp[pidx * n + k] : -1;
            }
        }
    }
    return true;
}

