/* 1oom-mp: the council is a plenary event (every empire is present), so stream the chamber state to
   ALL human players via the spectate channel -- they render it while waiting (shared synchronous
   view). The vote/accept stay per-human (decision RPC). Pointers are zeroed for transport. */
static void mp_election_relay(struct election_s *el, int kind)
{
    if (!g_mp_spectate_hook || !el || !el->g) { return; }
    uint8_t buf[1 + sizeof(struct election_s) + 256];
    int len = 1;
    buf[0] = (uint8_t)kind;
    if (kind == UI_MP_SPEC_COUNCIL) {
        struct election_s e = *el;
        e.g = NULL; e.uictx = NULL; e.buf = NULL; e.str = NULL;
        memcpy(buf + 1, &e, sizeof(e));
        len = 1 + (int)sizeof(e);
        /* 1oom-mp: el->str (the chamber announcement / vote tally / "X is now emperor" / "no
           majority" result banner) is a pointer into server memory, so the zeroed copy above leaves
           the client with nothing to draw -- no council text ever shows. Append the TEXT so the
           client can re-point el->str at its own copy (see mp_if_on_spectate). */
        {
            const char *s = el->str ? el->str : "";
            int slen = (int)strlen(s);
            if (slen > 255) { slen = 255; }
            memcpy(buf + len, s, (size_t)slen);
            buf[len + slen] = 0;
            len += slen + 1;
        }
    }
    for (player_id_t p = PLAYER_0; p < el->g->players; ++p) {
        if (IS_HUMAN(el->g, p)) { g_mp_spectate_hook(p, buf, len, 0/*best-effort: council frame is full state, self-heals*/); }
    }
}

void ui_election_start(struct election_s *el)
{
    mp_election_relay(el, UI_MP_SPEC_COUNCIL);
}

void ui_election_show(struct election_s *el)
{
    mp_election_relay(el, UI_MP_SPEC_COUNCIL);
    /* the council runs headless here with no pacing, so spectators would only ever see the latest
       frame before the next one / the tear-down. Hold each step so they can actually read it. */
    if (g_mp_spectate_hook) { usleep(900000); }
}

void ui_election_delay(struct election_s *el, int delay)
{
    if (g_mp_spectate_hook && (delay > 0)) { usleep((useconds_t)delay * 120000); }
}

/* 1oom-mp: the galactic-council vote + accept happen during resolution; ship the
   election state to the voting human's client and ask there (the struct's pointers
   are zeroed for transport and re-pointed client-side). Default outside MP unchanged. */
int ui_election_vote(struct election_s *el, int player_i)
{
    if (g_mp_decision_hook) {
        /* 1oom-mp: the vote is a private RPC, so the shared chamber would otherwise freeze on the last
           narration while this human decides -- spectators can't tell who they're waiting on. Stream a
           clear "Awaiting <Empire>..." frame to everyone first (cur_i already marks the voter). */
        if (g_mp_spectate_hook && el->g) {
            char wbuf[80];
            const char *saved = el->str;
            lib_sprintf(wbuf, sizeof(wbuf), "Awaiting the vote of %s...", el->g->emperor_names[player_i]);
            el->str = wbuf;
            mp_election_relay(el, UI_MP_SPEC_COUNCIL);
            el->str = saved;
        }
        struct election_s e = *el;
        e.g = NULL; e.uictx = NULL; e.buf = NULL; e.str = NULL;
        uint8_t req[sizeof(struct election_s) + 4];
        int32_t pi32 = player_i, vote = 0;
        memcpy(req, &e, sizeof(e));
        memcpy(req + sizeof(e), &pi32, 4);
        int r = g_mp_decision_hook(player_i, MP_DEC_ELECTION_VOTE, req, (int)sizeof(req), &vote, sizeof(vote));
        if (r >= (int)sizeof(vote)) { return vote; }
    }
    return 0;
}

bool ui_election_accept(struct election_s *el, int player_i)
{
    if (g_mp_decision_hook) {
        struct election_s e = *el;
        e.g = NULL; e.uictx = NULL; e.buf = NULL; e.str = NULL;
        uint8_t req[sizeof(struct election_s) + 4], resp = 0;
        int32_t pi32 = player_i;
        memcpy(req, &e, sizeof(e));
        memcpy(req + sizeof(e), &pi32, 4);
        int r = g_mp_decision_hook(player_i, MP_DEC_ELECTION_ACCEPT, req, (int)sizeof(req), &resp, 1);
        if (r >= 1) { return resp != 0; }
    }
    return false;
}

void ui_election_end(struct election_s *el)
{
    /* hold the final result on every spectator's screen before tearing the council down, otherwise
       the next turn's state load wipes it instantly and players never see who won. */
    if (g_mp_spectate_hook) { sleep(3); }
    mp_election_relay(el, UI_MP_SPEC_COUNCIL_END);
}

