/* 1oom-mp: the AI's diplomacy with a human runs through game_audience on this headless server;
   relay each ui_audience_* call to the human's client (au->ph) so they actually see the audience
   and answer. If au->ph isn't a connected human, the decision hook returns <0 and we fall back to
   the old auto-resolve default (0). Strings are sent as text since they may point at static
   game-string tables or the inline diplo_msg/strtbl_buf. */
static int16_t mp_audience_relay(uint8_t subtype, uint8_t ntpi, struct audience_s *au)
{
    if (!g_mp_decision_hook) { return 0; }
    static uint8_t req[8192];
    int pos = 0;
    req[pos++] = subtype;
    req[pos++] = ntpi;
    memcpy(req + pos, au, sizeof(*au)); pos += (int)sizeof(*au);
    uint16_t blen = au->buf ? (uint16_t)strlen(au->buf) : 0;
    if (blen > AUDIENCE_DIPLO_MSG_SIZE) { blen = AUDIENCE_DIPLO_MSG_SIZE; }
    memcpy(req + pos, &blen, 2); pos += 2;
    if (blen) { memcpy(req + pos, au->buf, blen); pos += blen; }
    uint8_t nstr = 0;
    while ((nstr < AUDIENCE_STR_MAX) && au->strtbl[nstr]) { ++nstr; }
    req[pos++] = nstr;
    for (int i = 0; i < nstr; ++i) {
        uint16_t l = (uint16_t)strlen(au->strtbl[i]);
        if (l > 255) { l = 255; }
        memcpy(req + pos, &l, 2); pos += 2;
        memcpy(req + pos, au->strtbl[i], l); pos += l;
    }
    req[pos++] = au->condtbl ? 1 : 0;
    if (au->condtbl) { for (int i = 0; i < nstr; ++i) { req[pos++] = au->condtbl[i] ? 1 : 0; } }
    uint8_t rsp[4];
    int r = g_mp_decision_hook(au->ph, MP_DEC_AUDIENCE, req, pos, rsp, (int)sizeof(rsp));
    if (r >= 2) { int16_t v; memcpy(&v, rsp, 2); return v; }
    return 0;
}

void ui_audience_start(struct audience_s *au) { mp_audience_relay(MP_AUD_START, 0, au); }
void ui_audience_show1(struct audience_s *au) { mp_audience_relay(MP_AUD_SHOW1, 0, au); }
void ui_audience_show2(struct audience_s *au) { mp_audience_relay(MP_AUD_SHOW2, 0, au); }
void ui_audience_show3(struct audience_s *au) { mp_audience_relay(MP_AUD_SHOW3, 0, au); }
int16_t ui_audience_ask2a(struct audience_s *au) { return mp_audience_relay(MP_AUD_ASK2A, 0, au); }
int16_t ui_audience_ask2b(struct audience_s *au) { return mp_audience_relay(MP_AUD_ASK2B, 0, au); }
int16_t ui_audience_ask3(struct audience_s *au) { return mp_audience_relay(MP_AUD_ASK3, 0, au); }
int16_t ui_audience_ask4(struct audience_s *au) { return mp_audience_relay(MP_AUD_ASK4, 0, au); }
void ui_audience_newtech(struct audience_s *au, int pi) { mp_audience_relay(MP_AUD_NEWTECH, (uint8_t)pi, au); }
void ui_audience_end(struct audience_s *au) { mp_audience_relay(MP_AUD_END, 0, au); }

